// ignore_for_file: avoid_relative_lib_imports

import 'dart:typed_data';

import 'package:test/test.dart';

import '../lib/src/utils.dart';
import '../lib/src/block.dart';

void main() {
  test('block parsing/serialization', () {
    final testnet4block0Hex =
        '';
    final testnet4block0 = Block.fromBytes(testnet4block0Hex.toBytes());
    final serialized0 = testnet4block0.toBytes().toHex();
    expect(serialized0, equals(testnet4block0Hex));
    expect(
      testnet4block0.header.hashNice(),
      equals(
        '00000000da84f2bafbbc53dee25a72ae507ff4914b867c565be350b0da8bf043',
      ),
    );
    expect(testnet4block0.header.version, equals(1));
    expect(
      testnet4block0.header.previousBlockHeaderHash,
      equals(Uint8List(32),
      ),
    );
    expect(testnet4block0.header.merkleRootHash.reverse(), equals('7aa0a7ae1e223414cb807e40cd57e667b718e42aaf9306db9102fe28912b7b4e'.toBytes()),);
    expect(testnet4block0.header.time, equals(1714777860));
    expect(testnet4block0.header.nonce, equals(393743547));
    expect(testnet4block0.header.nBits, equals(0x1d00ffff));
    expect(testnet4block0.transactions.length, equals(1));

    final testnet4block20090Hex = '';
    final testnet4block20090 = Block.fromBytes(testnet4block20090Hex.toBytes());
    final serialized20090 = testnet4block20090.toBytes().toHex();
    expect(serialized20090, equals(testnet4block20090Hex));
    expect(
      testnet4block20090.header.hashNice(),
      equals(
        '0000000000003d857ef88c4b4019f28d3d53cdd9a4b583bdd4c7c5a939b56ccb',
      ),
    );
    expect(testnet4block20090.header.version, equals(0x20000000));
    expect(
      testnet4block20090.header.previousBlockHeaderHash.reverse(),
      equals('000000000000205e0fde515d05e30b3f8482595f8bd115b258dbd74e735f30fd'.toBytes()),
    );
    expect(testnet4block20090.header.merkleRootHash.reverse(), equals('0d660cfb0f5bccaaf1ab954b7568db143242070ab5c3f954984faed2cced8ca4'.toBytes()),);
    expect(testnet4block20090.header.time, equals(1715378160));
    expect(testnet4block20090.header.nonce, equals(3700857824));
    expect(testnet4block20090.header.nBits, equals(0x1a3fffc0));
    expect(testnet4block20090.transactions.length, equals(13));
  });
}
